});

const fs = require('fs');

const item = $input.first();
const data = item.json;

const videoId = data.videoId || 'PI_temp';
const idx = data.imageIndex || 0;

// Cria o diretório
const tempDir = '/home/node/.n8n/temp/' + videoId;
if (!fs.existsSync(tempDir)) {
  fs.mkdirSync(tempDir, { recursive: true });
}

// 1. Verifica se o nó anterior mandou o arquivo binário
if (!item.binary || !item.binary.data) {
  throw new Error("Imagem não encontrada! O nó do Nano Banana não retornou o binário 'data'.");
}

// 2. Define o nome do arquivo (Note que o Nano Banana retornou um .png na sua imagem)
const imgFile = tempDir + '/img_' + String(idx).padStart(2, '0') + '.png';

// 3. Pega o arquivo binário da memória do n8n (que está em base64) e converte para Buffer
const fileBuffer = Buffer.from(item.binary.data.data, 'base64');

// 4. Salva o arquivo direto no disco
fs.writeFileSync(imgFile, fileBuffer);

// 5. Retorna o JSON atualizado e repassa o binário
return [{
  json: { 
    ...data, 
    imageLocalPath: imgFile, 
    imageSourceUrl: "binary_from_nanobanana" // Não há URL, veio direto do nó
  },
  binary: {
    data: item.binary.data
  }
}];

var shareData = $input.first().json;
var prev = $('Drive: Upload Image').first().json; // Aqui está o ID verdadeiro!

// Pass drive ID along with all original data
return [{
  json: {
    ...$('Download Image').first().json,
    _driveId: prev.id  // AQUI FOI A CORREÇÃO! Puxando do 'prev' em vez do 'shareData'
  }
}];

var allItems = $input.all();

// 1. Resgata os textos do nó correto antes do loop
var originalData = {};
try { 
  originalData = $("Prepare Image Prompts").first().json; 
} catch(e) {
  console.log("Aviso: Nó 'Prepare Image Prompts' não encontrado.");
}

// 2. Monta as imagens usando o ID que vem do input
var images = allItems.map(function(item, index) {
  // Pega o driveId que o nó "Set Drive ID" (dentro do loop) enviou
  var driveId = item.json._driveId || item.json.driveId || "FALTOU_O_ID";

  return {
    url: 'https://drive.google.com/uc?export=download&id=' + driveId,
    driveId: driveId,
    numero: index + 1
  };
});

return [{
  json: {
    videoId: originalData.videoId || 'PI_unknown',
    images: images,
    narracao: originalData.narracao || '',
    ctaText: originalData.ctaText || '',
    titulo: originalData.titulo || '',
    descricao: originalData.descricao || '',
    hashtags: originalData.hashtags || [],
    tema_jesus: originalData.tema_jesus || '',
    versiculo: originalData.versiculo || '',
    GOOGLE_AI_API_KEY: originalData.GOOGLE_AI_API_KEY || '',
    ELEVENLABS_API_KEY: originalData.ELEVENLABS_API_KEY || '',
    imagesReady: true
  }
}];

